INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 1, 110501, 24015, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 4, 4, "2030/12/17 14:59:59", 0.0, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 2, 110501, 24016, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 4, 1, "2030/12/17 14:59:59", 4.0, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("マジムンだらけで目が回るさ～！\nふらふらさ～！", 3, 110501, 24017, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 4, 4, "2030/12/17 14:59:59", 0.0, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 4, 110501, 24018, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 1, 2, "2030/12/17 14:59:59", 5.2, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 5, 110501, 24019, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 5, 6, "2030/12/17 14:59:59", 4.2, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 6, 110501, 24020, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 2, 2, "2030/12/17 14:59:59", 0.0, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 7, 110501, 24021, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 1, 6, "2030/12/17 14:59:59", 6.4, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 8, 110501, 24022, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 2, 2, "2030/12/17 14:59:59", 0.0, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 9, 110501, 24023, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 6, 3, "2030/12/17 14:59:59", 10.08, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 10, 110501, 24024, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 1, 2, "2030/12/17 14:59:59", 5.0, 0.0, 0.0, 24);
INSERT INTO `v1_b5a46d11f7617f50fb2f4c7188aa725999280c69de66889775371e4bd642cf2b` VALUES ("私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 11, 110501, 24025, 10021, "2019/07/31 12:00:00", "カオリ（サマー）", 2, 2, "2030/12/17 14:59:59", 0.0, 0.0, 0.0, 24);
